class MyQueue {
public:
    MyQueue() {

    }

    void push(int x) {
        stack1.push(x);
    }

    int pop() {
        while(stack2.empty() || stack2.top() != stack1.top()) {
            stack2.push(stack1.top());
            stack1.pop();
        }
        int res = stack2.top();
        stack2.pop();
        return res;
    }

    int peek() {
        while(stack2.empty() || stack2.top() != stack1.top()) {
            stack2.push(stack1.top());
            stack1.pop();
        }
        return stack2.top();
    }

    bool empty() {
        return stack1.empty() && stack2.empty();
    }
private:
    stack<int> stack1;
    stack<int> stack2;
};
